// Collection.js - UPDATED
import React, { useState } from "react";
import { motion } from "framer-motion";
import { useNavigate } from "react-router-dom";
import "../styles/Collection.css";
import dress from "../assets/images/auri_dress.jpg";

const items = [
  { 
    id: 1, 
    title: "Dress", 
    img: dress, 
    category: "dress",
    description: "Elegant and stylish dresses for every occasion. Perfect for summer outings and special events."
  },
  { 
    id: 2, 
    title: "Maxi Dress", 
    img: "https://images.unsplash.com/photo-1581044777550-4cfa60707c03?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80", 
    category: "maxi",
    description: "Flowy and comfortable maxi dresses. Ideal for casual wear, beach days, and relaxed outings."
  },
  { 
    id: 3, 
    title: "Jewellery", 
    img: "https://images.unsplash.com/photo-1515562141207-7a88fb7ce338?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1000&q=80", 
    category: "elegant",
    description: "Exquisite jewelry pieces to complement your style. From elegant necklaces to statement pieces."
  },
];

const Collection = () => {
  const [activeFilter, setActiveFilter] = useState("all");
  const navigate = useNavigate();

  const filteredItems = activeFilter === "all" 
    ? items 
    : items.filter(item => item.category === activeFilter);

  // Updated categories with proper mapping
  const categories = [
    { key: "all", label: "All" },
    { key: "dress", label: "Dress" },
    { key: "maxi", label: "Maxi Dress" },
    { key: "elegant", label: "Jewelry" }
  ];

  // Handle category filter click
  const handleCategoryClick = (categoryKey) => {
    setActiveFilter(categoryKey);

    // Navigate to specific collection pages based on category
    if (categoryKey === "dress") {
      navigate("/summer-collection");
    } else if (categoryKey === "maxi") {
      navigate("/casual-collection");
    } else if (categoryKey === "elegant") {
      navigate("/jewelry-collection");
    }
    // "all" stays on the current page
  };

  // Handle Quick View
  const handleQuickView = (item) => {
    if (item.category === "dress") {
      navigate("/summer-collection");
    } else if (item.category === "maxi") {
      navigate("/casual-collection");
    } else if (item.category === "elegant") {
      navigate("/jewelry-collection");
    }
  };

  return (
    <section id="collection" className="collection">
      <div className="container">
        <div className="section-title">
          <h2>Our Collection</h2>
          <p>Discover pieces that reflect your unique style and personality</p>
        </div>

        <div className="collection-filters">
          {categories.map(category => (
            <button
              key={category.key}
              className={`filter-btn ${activeFilter === category.key ? "active" : ""}`}
              onClick={() => handleCategoryClick(category.key)}
            >
              {category.label}
            </button>
          ))}
        </div>

        <motion.div 
          className="collection-grid"
          layout
        >
          {filteredItems.map((item) => (
            <motion.div
              key={item.id}
              className="card"
              whileHover={{ y: -10 }}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              viewport={{ once: true }}
            >
              <div className="card-image">
                <img src={item.img} alt={item.title} />
                <div className="card-overlay">
                  <motion.button 
                    className="quick-view-btn"
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    onClick={() => handleQuickView(item)}
                  >
                    Explore Collection
                  </motion.button>
                </div>
              </div>
              <div className="card-content">
                <h3>{item.title}</h3>
                <p className="description">{item.description}</p>

              </div>
            </motion.div>
          ))}
        </motion.div>
      </div> 
    </section>
  );
};

export default Collection;
